package core.webserver.org.apache.isis.core.webserver.internal;

public final class OptionHandlerPort implements OptionHandler { private Integer port ; static final String PORT_LONG_OPT = "port" ; static final String PORT_OPT = "p" ; public static String [ ] appendArg ( final String [ ] args , final int port ) { return ArrayExtensions . append ( args , "--" + PORT_LONG_OPT , "" + port ) ; } @ Override @ SuppressWarnings ( "static-access" ) public void addOption ( final Options options ) { OptionBuilder . withArgName ( "port" ) ; final Option option = OptionBuilder . hasArg ( ) . withLongOpt ( OptionHandlerPort . PORT_LONG_OPT ) . withDescription ( "port to listen on" ) . create ( OptionHandlerPort . PORT_OPT ) ; options . addOption ( option ) ; } @ Override public boolean handle ( final CommandLine commandLine , final BootPrinter bootPrinter , final Options options ) { final String portStr = commandLine . getOptionValue ( OptionHandlerPort . PORT_OPT ) ; if ( portStr != null ) { port = Integer . parseInt ( portStr ) ; } return true ; } @ Override public void prime ( final IsisConfigurationBuilder isisConfigurationBuilder ) { if ( port == null ) { return ; } isisConfigurationBuilder . add ( WebServerConstants . EMBEDDED_WEB_SERVER_PORT_KEY , "" + port ) ; } }